# ui/logo.py — THRESHOLD · Logo embarqué en base64
# Dragon fond transparent, légèrement aéré (6% padding).
# ─────────────────────────────────────────────────────────────────────────────

LOGO_80 = ""
"""Base64 PNG 80×80 — pour écrans profil / hero."""

LOGO_36 = ""
"""Base64 PNG 36×36 — pour dashboard / nav."""


def logo_image(size: int = 80):
    """Retourne un ft.Image avec le logo THRESHOLD embarqué."""
    import base64 as _b64
    import flet as ft
    b64 = LOGO_80 if size >= 50 else LOGO_36
    return ft.Image(
        src=_b64.b64decode(b64),
        width=size,
        height=size,
        fit=ft.BoxFit.CONTAIN,
    )
